#!/usr/bin/env python3
"""
MKT Original Commentary — Ecclesiastes chapters 1–4 (81 missing verses)
Run: python3 scripts/zc-original-ecclesiastes-1-4-full.py

Source data used:
- data/interlinear/ecclesiastes.json
- data/translation/draft/mediating/ecclesiastes.json (MKT text for quoting)
- data/translation/glossary-hebrew.json (semantic ranges)

Key decisions in this range:
- hevel (H1892): rendered "futility" in MKT; literally "breath/vapor"; the LXX mataiotes
  connects to Rom 8:20. Noted throughout without repeating the full etymology.
- yitron (H3504): "lasting gain" in MKT; unique to Ecclesiastes (not found elsewhere in OT)
- Qohelet (H6953): "Teacher" in MKT (assembler/caller of assembly); retained as "the Teacher"
- amal (H5999): labor/toil carrying the burden of weariness; also the fruit/product of that labor
- ruach (H7307): "wind" in cyclical observations (1:6, 14); "spirit" in 3:21; same word both ways
- olam (H5769): normally "forever/eternity/age"; uniquely placed "in the human heart" at 3:11
- miqreh (H4745): "event/fate" — the one thing that happens to all regardless of wisdom
- inyan (H6045): "business/task/affair" — a word nearly unique to Ecclesiastes in OT
- z'man (H2165): appointed time (3:1) — more precise than generic "time" (et/H6256)
- helqi (H2506): "portion/reward" — the carpe diem counsel: take your portion as God's gift
- The MKT's "chasing the wind" renders re'ut/rayon ruach (feeding on wind/striving after wind)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ECCLESIASTES = {
    "1": {
        "1": "<p><strong>Dibrei Qohelet ben-David melek biYerushalayim</strong> — 'The words of Qohelet, son of David, king in Jerusalem.' The title introduces the speaker by function rather than name: <em>Qohelet</em> (H6953) is a feminine participial noun from <em>qahal</em> (to assemble), meaning 'the one who assembles' or 'the preacher/assembler of an audience.' The feminine form is unusual for a title referring to a male king — it may function as an abstract office title (cf. <em>Sophereth</em>, Ezra 2:55). The Solomonic frame ('son of David, king in Jerusalem') is never made fully explicit by name; 'Qohelet' as speaker is maintained throughout. This allows the book to function as royal wisdom literature without being locked to Solomon's historical particulars.</p>",
        "3": "<p><strong>Mah-yitron la'adam</strong> — 'What lasting gain does a person have?' The word <em>yitron</em> (H3504) is used ten times in Ecclesiastes and almost nowhere else in the OT (once in Exod 16:23 in an unrelated sense). It carries a commercial nuance: 'surplus,' 'profit,' 'net advantage after deducting costs.' The Teacher is asking whether there is a net positive return on all human investment. The prepositional phrase <em>betahat hashemesh</em> ('under the sun') appears 29 times in Ecclesiastes and is the book's self-imposed limit: it marks the sub-eschatological perspective, what can be known within the frame of mortal, earthly existence without resurrection or final judgment. The question of <em>yitron</em> is therefore precisely bounded: not 'is there value in life?' but 'is there net advantage within the closed system of existence under the sun?'</p>",
        "4": "<p><strong>Dor holekh ve-dor ba ve-ha'aretz le'olam amedet</strong> — 'One generation goes and another generation comes, but the earth remains forever.' The contrast is structurally precise: human generations are characterized by movement — <em>holekh</em> (going) and <em>ba</em> (coming) — while the earth <em>amedet</em> (stands firm, endures). The verb <em>amad</em> for the earth's permanence contrasts with the transience of <em>dor</em> (generation). The phrase <em>le'olam</em> ('forever') here means 'continuously, without end' — it characterizes the earth's persistence, not its ultimate ontological status. The irony is that what appears most solid and permanent (the earth) outlasts what considers itself most significant (successive human generations).</p>",
        "5": "<p><strong>Ve-zarach hashemesh uba hashemesh</strong> — 'The sun rises and the sun sets.' The root <em>zarach</em> (to rise/shine) is used for both sunrise and the dawn of glory elsewhere (Isa 60:1-2: 'arise, shine, for your light has come'). Here it merely marks the relentless repetition of the solar circuit. <em>El-miqomo shoef zarach sham</em> — 'hurrying to its place where it rises' — the verb <em>sha'af</em> means to pant or gasp (used for the panting of animals). The sun is personified as a gasping runner who cannot stop. The Teacher's rhetoric deliberately flattens what would normally be celebrated (sunrise) into evidence of endless futile repetition.</p>",
        "6": "<p><strong>Holekh el-darom ve-sovev el-tzafon sovev sovev holekh haruach</strong> — 'The wind blows south, then turns north; it whirls around and around.' The word <em>ruach</em> (H7307) means both 'wind' and 'spirit/breath.' This double meaning runs through Ecclesiastes: the wind's aimless circulation (1:6) and 'chasing the wind' (1:14, <em>re'ut ruach</em>) anticipate the deep question of ch 3:21: 'Who knows whether the spirit [<em>ruach</em>] of man goes upward?' The same word that describes futile circular motion (wind circling) describes what is potentially immortal in the human person. <em>Ve-al-sevivotav shav haruach</em> — 'the wind returns to its circuits' — <em>sevivotav</em> from <em>savav</em> (to go around/turn), the same root as the wind's 'whirling'; there is no progress, only return.</p>",
        "7": "<p><strong>Kol-hanechalim holkhim el-hayam ve-hayam einenu male</strong> — 'All the rivers run to the sea, yet the sea is never full.' The image is of an apparently purposeful process (rivers flowing toward an obvious destination) that produces no net result (the sea fills no further). <em>El-maqom shehanechalim holkhim sham hem shavim laleshet</em> — 'to the place where the rivers go, they return to flow again.' The verb <em>shav</em> (to return) describes both a physical cycle and a moral one throughout the wisdom literature: the righteous 'return' to God (Ps 90:3), the fool 'returns' to his folly (Prov 26:11). Here the rivers' return is merely hydrological — they evaporate, condense, and fall again — but the Teacher uses this mechanistic cycle as an image for the futility of all output that produces no permanent gain.</p>",
        "8": "<p><strong>Kol-hadvarim ye'eim</strong> — 'All things are wearisome' or 'All words are wearisome.' The noun <em>devarim</em> (H1697) means both 'words/speech' and 'things/matters' — the ambiguity may be deliberate: both the things of life and the words used to describe them exhaust without satisfying. <em>Lo yuchal ish ledaber</em> — 'no one can fully express it' — the verb <em>dibber</em> connects back to <em>devarim</em>: the things are too wearisome to speak of, yet also the words are what prove insufficient. <em>Lo-tiśba ayin lir'ot ve-lo-timale ozen mishmo'a</em> — 'the eye is not satisfied with seeing, nor the ear full with hearing.' <em>Sava</em> (satisfied/full) links to the sea that is never 'full' (v.7, <em>einenu male</em>): the same Hebrew root family describes the fullness the sea never achieves and the satisfaction the eye never reaches.</p>",
        "9": "<p><strong>Mah-shehayah hu sheyih-yeh</strong> — 'What has been is what will be.' The construction is emphatic repetition: <em>shehayah</em> (what has been) = <em>sheyih-yeh</em> (what will be). This is absolute cyclical determinism stated as wisdom observation. <em>Ve-ein kol-chadash tahat hashemesh</em> — 'there is nothing new under the sun.' <em>Chadash</em> (new) is the same root as in the covenant promise 'I will make a new covenant' (Jer 31:31) and the eschatological promise 'I make all things new' (Rev 21:5/Isa 43:19). The Teacher's claim is precisely bounded by his 'under the sun' frame — the new thing that breaks the cycle cannot appear within the closed system of the mortal world; the Teacher is right about the earthly frame and wrong only in that he cannot see beyond it.</p>",
        "10": "<p><strong>Yesh davar sheyomer re'eh zeh chadash hu</strong> — 'Is there a thing of which one says, &#8216;See, this is new&#8217;?' The rhetorical question pattern is characteristic of Ecclesiastes' diatribe style: an imagined objector is entertained and then dismissed. <em>Kebar hayah le'olamim</em> — 'It has already been in the ages before us.' <em>Olamim</em> (plural of <em>olam</em>) = 'the ages' or 'antiquity' — time stretching back before memory. The Teacher's logic: what appears new to the present generation is merely beyond living memory (cf. v.11). This is observational wisdom, not philosophical nihilism; its limits become clear in v.11.</p>",
        "11": "<p><strong>Ein zikaron larishonim</strong> — 'There is no remembrance of earlier people.' The noun <em>zikaron</em> (H2146) — memorial, remembrance, record — is related to <em>zakhar</em> (to remember), the root of the covenant promise 'I will remember my covenant' (Gen 9:15; Exod 2:24). YHWH's remembrance is what sustains the covenant when human memory fails. The Teacher identifies what is lost 'under the sun': no human mechanism exists to preserve memory across generations. <em>Ve-gam barishonim shehyu</em> — 'nor will there be among those yet to come' — the symmetry is complete: past generations are forgotten and future generations will forget us. This is the anthropological situation that the covenant's memorial practices (<em>zikaron</em>, the Passover, the Lord's Supper) exist to address.</p>",
        "12": "<p><strong>Ani Qohelet hayiti melek al-Yisrael biYerushalayim</strong> — 'I, the Teacher, was king over Israel in Jerusalem.' The past tense <em>hayiti</em> ('I was') has puzzled interpreters: if the Teacher is currently king, why past tense? Some take it as a literary device (Qohelet is not actually Solomon, but a wisdom persona using his voice after-the-fact). Others read it as Solomon writing from old age looking back. The uncertainty is part of the book's rhetorical design: the Solomonic frame gives the experiment maximum epistemic authority (who could have done this experiment better?) without claiming to be Solomon's straightforward autobiography. The past tense emphasizes completed experience: 'I have been king — I know from the inside.'</p>",
        "13": "<p><strong>Ve-natati et-libbi lidrosh ve-latour bahokmah</strong> — 'I applied my heart to seek and to search out by wisdom.' The verb pair <em>darash</em> (seek/inquire) + <em>tur</em> (explore/scout) describes intensive, systematic investigation — the same verbs used for the spies who scouted Canaan (Num 13:25). <em>Inyan ra' hu asher natan Elohim livnei ha'adam la'anot bo</em> — 'It is an unhappy business that God has given to the children of man to be busy with.' <em>Inyan</em> (H6045) is nearly unique to Ecclesiastes (occurs 8 times here, once in Sirach, nowhere else in the OT canon). It means business/occupation/task. The characterization of this investigating task as <em>ra'</em> (evil/unhappy) is the Teacher's verdict on what it is to be a questing human under the sun: God has given us a vocation of inquiry that, within the earthly frame, leads only to the recognition of limits.</p>",
        "14": "<p><strong>Ra'iti et-kol-hama'asim sheassho tahat hashemesh</strong> — 'I have seen all the works that are done under the sun.' The verb <em>ra'ah</em> (to see/observe) is the Teacher's characteristic cognitive tool — used ~47 times in Ecclesiastes. He is an empiricist: he tests claims by observation. <em>Re'ut ruach</em> — 'chasing the wind' (or 'feeding on wind' — the verb <em>ra'ah</em> can mean 'to pasture/feed'). This phrase appears throughout chs. 1-6 as the verdict on each futile enterprise. The double meaning — chasing what cannot be caught, feeding on what has no substance — captures the Teacher's tone. The wind cannot be grabbed or accumulated; the labor that produces no lasting gain is as insubstantial as attempting to hold wind in one's fist.</p>",
        "15": "<p><strong>Me'uvat lo-yuchal litkon</strong> — 'What is crooked cannot be made straight.' The verb <em>taqan</em> (to make straight/set right) appears only 3 times in the OT, two of them in Ecclesiastes (1:15; 7:13). The passive participle <em>me'uvat</em> (twisted/bent) describes a condition imposed from outside — the world as it currently is has been bent. The Teacher does not explain why the world is bent (that would require Gen 3's frame), but he recognizes the datum: within the 'under the sun' perspective, the crooked cannot be straightened by human wisdom. <em>Ve-hemron lo yuchal lehimanol</em> — 'and what is lacking cannot be counted' — <em>hemron</em> is a hapax legomenon (occurs once only); the sense is 'what is missing/deficient.' The Teacher identifies a fundamental insufficiency in the created order as he experiences it.</p>",
        "16": "<p><strong>Hibarthi ani im-libbi lemor ani hineh higdalti ve-horafti hokmah al-kol asher-hayah lefanai al-Yerushalayim</strong> — 'I said to myself, &#8220;I have acquired more wisdom than anyone who ruled before me.&#8221;' The self-address (<em>dibarthi ani im-libbi</em> = 'I spoke with my heart') is one of Ecclesiastes' characteristic rhetorical devices; the 'heart' is the seat of the self, and the Teacher's internal dialogue becomes the structure of his investigation. The boast 'more than anyone before me in Jerusalem' maximizes the scope of the experiment: if Solomonic wisdom cannot find <em>yitron</em>, no wisdom can. <em>Ve-libbi ra'ah harbeh hokmah ve-da'at</em> — 'my heart has had great experience of wisdom and knowledge' — <em>da'at</em> (knowledge) is paired with <em>hokmah</em> (wisdom) as the two cognitive virtues; the Teacher has pursued both to the maximum.</p>",
        "17": "<p><strong>Ve-etna libbi lada'at hokmah ve-lada'at holalot ve-sikhlet</strong> — 'I applied my heart to know wisdom, and to know madness and folly.' The pairing of wisdom with its opposites — <em>holalot</em> (madness/acting-foolishly) and <em>sikhlet</em> (folly/stupidity) — shows the Teacher's comprehensive methodology: he does not study wisdom in isolation but in contrast with its extremes. <em>Yada'ti shegam-zeh hu ra'yon ruach</em> — 'I perceived that this also is chasing the wind.' The word <em>ra'yon</em> is a variant form of <em>re'ut</em> (pursuit/striving) — both appear in Ecclesiastes for 'chasing the wind.' The conclusion: the pursuit of wisdom itself, as an end in itself, within the 'under the sun' frame, produces the same verdict. Wisdom is good but insufficient to achieve <em>yitron</em>.</p>",
        "18": "<p><strong>Ki be-rov hokmah rov ka'as</strong> — 'For in much wisdom is much vexation.' The word <em>ka'as</em> (H3708) means grief, vexation, anger — the emotional state of frustration. Wisdom, the Teacher finds, does not deliver contentment; it delivers the expanded capacity to perceive what is wrong with the world, which is its own form of suffering. <em>Ve-yosef da'at yosef makhov</em> — 'and whoever increases knowledge increases sorrow.' The verb <em>yosef</em> (to add/increase) also spells the name Joseph — a word-play tradition observed in rabbinic commentary, though the primary meaning is straightforward. <em>Makhov</em> (H4341) means grief/pain — physical or emotional. The paradox: the cure (wisdom and knowledge) exacerbates the disease (awareness of futility). This is not anti-intellectualism but a precise observation about the limits of wisdom within the post-fall, sub-eschatological frame.</p>"
    },
    "2": {
        "1": "<p><strong>Amarthi ani be-libbi lekha na' anasekha be-simha ure'eh be-tov</strong> — 'Come now, I will test you with pleasure; enjoy yourself.' The verb <em>nasah</em> (to test/try) introduces the pleasure experiment: the Teacher applies his empirical method to hedonism. <em>Be-simha</em> (in pleasure/joy) — this word <em>simha</em> (H8057) later becomes the Teacher's positive counsel (2:10, 26; 3:12, 22; etc.): joy in one's work is God's gift. Here the Teacher tests whether pleasure as a comprehensive life-strategy produces <em>yitron</em> — it does not. <em>Ve-hineh gam-hu havel</em> — 'but this also was futility.' The structural formula 'this also was <em>hevel</em>' (or 'this also is chasing the wind') marks each section of the Royal Experiment with the same verdict.</p>",
        "2": "<p><strong>Le-sikhok amarthi mehulal</strong> — 'I said of laughter, &#8220;It is madness.&#8221;' <em>Mehulal</em> is the pual (passive intensive) participle of <em>halal</em> (to praise/to be foolish) — meaning 'madness' in this negative sense. The same root gives the common word <em>hallelujah</em> (praise the LORD): laughter here is the degenerate form of what was made for praise. <em>Ve-la-simha mah-zoh oset</em> — 'and of pleasure, &#8220;What does this achieve?&#8221;' The question uses <em>oset</em> from <em>asah</em> (to do/make) — what does pleasure <em>make</em>? The implication: pleasure is sterile, it produces nothing.</p>",
        "3": "<p><strong>Tarthi be-libbi limshokh bayain et-besari</strong> — 'I searched with my heart how to cheer myself with wine.' <em>Tarthi</em> is from <em>tur</em> (to explore/scout) — the same verb as 1:13; this is systematic exploration, not mere indulgence. <em>Ve-libbi noheig ba-hokmah</em> — 'my heart guiding me with wisdom' — the Teacher's method is crucial: he does not abandon wisdom while exploring pleasure but uses wisdom as the guide. This is the meaning of 'testing' (<em>nasah</em>) pleasure: a wisdom-governed experiment, not mere hedonism. <em>Ve-le'ehaz be-sikhlet</em> — 'and how to take hold of folly' — taking hold of folly while maintaining wisdom is the experimental design. <em>Ad asher ere mah-tov livnei ha'adam asher ya'asu tahat hashamayim</em> — 'until I might see what was good for the children of man to do under heaven during the few days of their life.' Note <em>tahat hashamayim</em> (under heaven) rather than <em>tahat hashemesh</em> (under the sun) — a slight variation; 'heaven' emphasizes the dome above while 'sun' emphasizes the light source.</p>",
        "4": "<p><strong>Higdalti ma'asai baniti li batim</strong> — 'I made great works: I built houses for myself.' The self-referential <em>li</em> ('for myself') appears repeatedly in vv. 4-8 — a deliberate accumulation: the Royal Experiment is characterized by self-oriented acquisition. <em>Nata'ti li keramim</em> — 'I planted vineyards for myself.' The scale of the experiment is Solomonic: 1 Kings 7 describes Solomon's building projects; the Teacher claims to have done all of it. The self-reference also sets up the verdict: 'for myself' is precisely the orientation that the Teacher discovers is futile — it produces <em>yitron</em> for no one when death transfers it all.</p>",
        "5": "<p><strong>Asiti li ganot u-pardesim</strong> — 'I made gardens and parks for myself.' The word <em>pardes</em> (H6508) is a loanword from Persian (<em>pairi-daeza</em> = enclosed garden/park) — one of the OT's few Persian loanwords, suggesting the book reached its final form in the Persian period. In the NT, <em>paradeisos</em> (garden of God, Paradise) derives from this same Persian root via Greek (Luke 23:43; Rev 2:7). The Teacher's constructed pleasure garden is a shadow of what was lost in Eden and promised in the new creation. <em>Ve-nata'ti bahem etz kol-peri</em> — 'and planted in them all kinds of fruit trees' — the abundance of Eden (Gen 2:9: 'every tree') echoes in the Teacher's constructed garden; the human impulse to recreate paradise is precisely what the experiment tests.</p>",
        "6": "<p><strong>Asiti li berekot mayim</strong> — 'I made pools from which to water the forest of growing trees.' The act of water management — pools fed from springs to irrigate an artificial forest (<em>ya'ar</em>) — requires comprehensive control over the environment: engineering, labor, resource. The scale of hydraulic infrastructure in the Ancient Near East was a sign of royal power (cf. Hezekiah's tunnel, 2 Kgs 20:20). The Teacher lists this achievement as evidence of his experimental scope, then negates it entirely in v.11.</p>",
        "7": "<p><strong>Qaniti avadim ve-shfachot</strong> — 'I bought male and female servants.' The verb <em>qanah</em> (to buy/acquire) is the same word disputed at Prov 8:22 ('the LORD possessed/created me'). Here it unambiguously means commercial acquisition. The Teacher's accumulation of servants, livestock, and wealth is the comprehensive test of whether material advantage creates lasting gain. <em>Gam-miqneh baqar va-tzon harbeh hayah li mi-kol shehayu lefanai biYerushalayim</em> — 'I also had great herds of cattle and flocks of sheep — more than anyone before me in Jerusalem.' The superlative ('more than anyone before me') is the marker of an experiment that covers the maximum possible scope; any lesser accumulation could be dismissed as not truly testing the question.</p>",
        "8": "<p><strong>Kafatsi li gam-kesef ve-zahav</strong> — 'I also gathered for myself silver and gold.' <em>Kafatsi</em> is from <em>kafah</em> — to skim/scrape together; the word emphasizes accumulation by relentless gathering. <em>Segulat melakhim ve-hamdinot</em> — 'the treasures of kings and provinces.' <em>Segulah</em> (H5459) is the covenant word for Israel as God's 'treasured possession' (Exod 19:5; Deut 7:6; Mal 3:17). Here it refers to material wealth — the Teacher has accumulated the nations' treasures as an experiment. The word's covenant resonance (Israel as God's <em>segulah</em>) creates ironic contrast: the Teacher collects a <em>segulah</em> of material goods, which will prove <em>hevel</em>; the divine <em>segulah</em> of a redeemed people is what cannot be declared vanity.</p>",
        "9": "<p><strong>Ve-gadalthi ve-hosafti mi-kol asher-hayah lefanai biYerushalayim</strong> — 'So I became greater than all who were before me in Jerusalem.' <em>Gadal</em> (to become great) and <em>yasaf</em> (to add/increase) describe compound growth. <em>Af-hokmati amdah li</em> — 'and my wisdom also remained with me.' This is the key methodological claim: the Teacher did not abandon wisdom during the pleasure experiment. He did not become a hedonist; he maintained his capacity for evaluation. The experiment's design requires this: only someone who retains wisdom can accurately evaluate whether pleasure produces <em>yitron</em>.</p>",
        "10": "<p><strong>Ve-khol asher sha'alu einai lo atzalthi mehem</strong> — 'And whatever my eyes desired I did not withhold from them.' The verb <em>atzal</em> (to withhold) is the same root used of Abraham who 'did not withhold' his son Isaac (Gen 22:12, <em>lo chatsakta</em>). The Teacher's self-indulgence is total: nothing the eye desired was refused. <em>Ki-libbi samach mi-kol amali ve-zeh hayah helqi mi-kol amali</em> — 'for my heart found pleasure in all my toil — and this was my reward for all my toil.' <em>Helqi</em> (H2506) — my portion/share — is a key word in Ecclesiastes' positive counsel. The Teacher discovers that joy in the process of work is itself the reward: not the product accumulated, but the experience of working with pleasure is the <em>helqi</em>, the portion that actually belongs to one.</p>",
        "11": "<p><strong>Ve-faniti ani be-khol-ma'asai sheasu yadai</strong> — 'Then I considered all that my hands had done.' The verb <em>panah</em> (to turn/face) describes a deliberate reorientation of attention: the Teacher turns to evaluate what the accumulation experiment has produced. <em>Ve-hineh hakol havel ure'ut ruach</em> — 'all was futility and chasing the wind.' <em>Re'ut ruach</em> — the MKT renders this 'chasing the wind'; the word <em>re'ut</em> (from <em>ra'ah</em>, to feed/shepherd) might mean 'feeding on wind' — consuming what has no substance. <em>Ve-ein yitron tahat hashemesh</em> — 'there was nothing to be gained under the sun.' The exact phrase from 1:3 (<em>mah yitron</em>) closes this subsection: the experiment yields the predicted result. The repetition is structural, not literary laziness.</p>",
        "12": "<p><strong>Ve-faniti ani lir'ot hokmah ve-holalot ve-sikhlet</strong> — 'So I turned to consider wisdom, madness, and folly.' The Teacher pivots from the Royal Experiment to comparative reflection. <em>Ki mah ha'adam sheyavo ahar hamelekh</em> — 'For what can the man who comes after the king do?' The question has been read as: (a) no one can replicate the royal experiment at this scale, or (b) the successor king (3:16-4:16 takes up this motif) faces the same vanity. <em>Et asher-kvar ashuhu</em> — 'only what has already been done' — the heir inherits the fruits without the process, and can add nothing beyond what the royal accumulator has already done. This connects to the 'no new thing' (1:9) motif.</p>",
        "13": "<p><strong>Ve-ra'iti ani she-yesh yitron la-hokmah min-ha-sikhlet</strong> — 'Then I saw that wisdom excels folly.' The word <em>yitron</em> (advantage/profit) here describes wisdom's superiority over folly — but notice the context: wisdom <em>has</em> yitron, but this yitron is not the same as the ultimate <em>yitron</em> under the sun that the book is seeking. Wisdom is genuinely better than folly; the Teacher does not deny this. <em>Ke-yitron ha'or min-ha-choshekh</em> — 'as light excels darkness.' The comparison (<em>ke-yitron</em> = 'as the advantage of') is an analogy: wisdom over folly is like light over darkness. But as vv. 14-16 will show, this advantage does not survive the one event that equalizes both wise and foolish: death.</p>",
        "14": "<p><strong>He-chakham einav be-rosho ve-ha-kesil ba-choshekh holekh</strong> — 'The wise person has his eyes in his head, but the fool walks in darkness.' The idiom 'eyes in his head' means attentiveness and perceptive awareness — the wise person sees where he is going. The fool (<em>kesil</em>, H3684 = the dull/stubborn fool, one who acts against known wisdom) walks in the dark. <em>Ve-yadati gam-ani she-miqreh echad yiqreh et-kulam</em> — 'Yet I also perceived that the same event happens to all of them.' The word <em>miqreh</em> (H4745) — 'event/fate/lot' — is key to Ecclesiastes' anthropology. It occurs 7 times (2:14, 15; 3:19 [x3]; 9:2, 3) and always describes the common death that erases all distinctions. Wisdom's advantage (eyes in the head) does not alter <em>miqreh</em>.</p>",
        "15": "<p><strong>Ve-amarthi ani be-libbi ke-miqreh ha-kesil gam-ani yiqreh li</strong> — 'What happens to the fool will happen to me also.' The Teacher's logic is unsentimental: if both the wise and the foolish die the same death, what is the practical <em>yitron</em> of wisdom in the long run? <em>La-mah chakhamti ani az yoter</em> — 'So why was I so very wise?' <em>Yoter</em> (H3148) means 'exceedingly/more/exceeding' — the superlative wisdom experiment was pointless if death erases the advantage. <em>Ve-dibarti be-libbi she-gam-zeh havel</em> — 'and I said in my heart that this also is futility.' The self-address formula again; the Teacher's internal monologue is the structure of the experiment's evaluation.</p>",
        "16": "<p><strong>Ki ein zikaron le-chakham im-ha-kesil le'olam</strong> — 'For there is no lasting remembrance of the wise any more than of the fool.' The word <em>zikaron</em> (memorial/remembrance) carries the weight of the covenant memorial system: what YHWH 'remembers' is sustained; what has no <em>zikaron</em> passes from existence as if it had never been. The Teacher's point: both wise and foolish leave no permanent human memorial; future generations will not distinguish them. <em>Ve-eikh yamut he-chakham im-ha-kesil</em> — 'How does the wise man die? Just like the fool.' The parallel death equalizes all human achievement. The Teacher is not denying that wisdom is better (v.13); he is denying that wisdom achieves the immortality of the memorial that would constitute <em>yitron</em>.</p>",
        "17": "<p><strong>Ve-sane'ti et-ha-chayyim</strong> — 'So I hated life.' The verb <em>sane'</em> (to hate) is strong: the Teacher has moved from frustration to something like existential revulsion. This is the emotional nadir of the Royal Experiment — not a philosophical conclusion but a felt response to the futility of all he has accumulated and observed. <em>Ki ra alay hama'aseh sheassoh tahat hashemesh</em> — 'because what is done under the sun seemed evil to me.' <em>Ra</em> (evil/bad) is the Teacher's evaluative word for what the futility-saturated world presents. <em>Ki hakol havel ure'ut ruach</em> — 'for all is futility and chasing the wind.' The full verdict formula closes the subsection. The Teacher's 'hatred of life' is not suicidal — it is the honest recognition that life 'under the sun,' without eschatological frame, is insufficient ground for sustained joy.</p>",
        "18": "<p><strong>Ve-sane'ti ani et-kol amali sheani amel tahat hashemesh</strong> — 'And I hated all my toil in which I had labored under the sun.' The word <em>amel</em> (H5998, to labor/toil) gives the noun <em>amal</em> (H5999) — used 35 times in Ecclesiastes; it means both the activity of laboring and the product of that labor. <em>She-ani amel tahat hashemesh</em> — 'in which I had labored under the sun' — the repetition of the laboring verb emphasizes the investment of self. <em>She-eni'chennu la'adam sheyihyeh acharai</em> — 'because I must leave it to the man who comes after me.' The problem of inheritance: the accumulator cannot control what the heir does with what is inherited. The wealth passes, but not the wisdom that produced it. This is one of the book's most humanly piercing observations about death and its consequences.</p>",
        "19": "<p><strong>U-mi yode'a ha-yih-yeh chakham o sakal</strong> — 'And who knows whether he will be wise or foolish?' The phrase <em>mi yode'a</em> ('who knows?') is a characteristic Ecclesiastes interrogative marking epistemological uncertainty (cf. 3:21; 6:12; 8:1). The heir might be a wise steward of the inheritance or a fool who dissipates it — the accumulator cannot know. <em>Vi-yishlet be-khol amali</em> — 'yet he will have control over all the fruit of my toil' — the verb <em>shalat</em> (to have dominion/control) echoes Gen 1:28 (<em>radah</em>/dominion); the heir exercises dominion over what the accumulator's wisdom produced. <em>Gam-zeh havel</em> — 'this also is futility.' The brevity of the conclusion matches the bitterness of the insight: a single phrase marks one of the human condition's most frustrating realities.</p>",
        "20": "<p><strong>Ve-savothi ani le-ya'esh libbi</strong> — 'So I turned about and gave my heart up to despair.' <em>Savothi</em> (from <em>savav</em>, to go around/turn) recalls the circular motions of 1:6 (the wind whirling), now applied to the Teacher himself: he turns, as everything turns, in a cycle that goes nowhere. <em>Ya'esh</em> (despair/hopelessness) — the noun is used only twice in the OT (here and Job 17:11). <em>Al-kol ha-amal sheamalti tahat hashemesh</em> — 'over all the toil at which I had labored under the sun.' The preposition <em>al</em> ('over') with despair: the Teacher's despair is directed specifically at the accumulated labor, not at life generically. His despair is as precise as his analysis.</p>",
        "21": "<p><strong>Ki yesh adam she-amalo be-hokmah uve-da'at uve-kishron</strong> — 'Because sometimes a person who labored with wisdom and knowledge and skill.' The triple characterization — wisdom, knowledge, skill (<em>kishron</em>, H3788, efficiency/advantage) — describes the ideal worker. <em>Ve-le'adam shelo amal-bo yitnennu helqo</em> — 'must leave everything to someone who did not work for it at all.' <em>Helqo</em> (his portion) — the concept of <em>helq</em> reappears: the heir receives a <em>helq</em> he did not earn, while the accumulator's portion (<em>helq</em>) that he earned through wisdom goes with him to death. <em>Gam-zeh havel vera'ah rabbah</em> — 'this also is futility and great evil.' The formula intensifies: not just <em>havel</em> but <em>vera'ah rabbah</em> (great evil) — the unjust distribution of the fruits of wisdom is the worst category the Teacher has yet assigned.</p>",
        "22": "<p><strong>Ki mah-hoveh la'adam be-khol amalo</strong> — 'For what does a man get from all his toil?' The word <em>hoveh</em> (H1933) — 'what comes to' or 'what befalls' — is an unusual form; some manuscripts read <em>yih-yeh</em> (what will be). The question is the same as 1:3 (<em>mah yitron</em>) but sharpened: not 'what lasting gain' but 'what actually arrives/comes to the man?' <em>U-vera'yon libbi shehu amel tahat hashemesh</em> — 'and striving of heart with which he labors under the sun.' <em>Ra'yon libbi</em> (striving of his heart) — the word <em>ra'yon</em> is related to <em>re'ut ruach</em> (chasing the wind): the inner striving and the outer metaphor are from the same root.</p>",
        "23": "<p><strong>Ki khol-yamav makhavim ve-ka'as inyano</strong> — 'For all his days are full of sorrow, and his work is grief.' <em>Makhavim</em> (sorrows/pains) — plural of <em>makhov</em> (H4341, grief/pain), same word as 1:18: the Teacher returns to his earlier observation. <em>Inyan</em> again: the 'business' of life is grief. <em>Gam-ba-layla lo-shakhav libboh</em> — 'even at night his heart does not rest.' The heart (<em>lev</em>) is the organ of thought and evaluation in Hebrew psychology; it does not stop working even when the body rests. <em>Gam-zeh havel hu</em> — 'this also is futility.' The relentlessness of sorrow — no rest even at night — is itself characterized as <em>hevel</em>.</p>",
        "24": "<p><strong>Ein tov ba'adam sheyokhal ve-shata ve-hera'ah et-nafsho be-amalo</strong> — 'There is nothing better for a person than to eat and drink and find enjoyment in his toil.' The phrase <em>ein tov</em> ('there is nothing better') introduces the carpe diem counsel that recurs throughout Ecclesiastes (3:12, 22; 5:18; 8:15; 9:7-9). The MKT's 'find enjoyment in his toil' renders <em>hera'ah et-nafsho</em> — literally, 'to cause his soul/life to see good' — the nefesh (H5315, soul/life/self) finding its experience of the good. <em>Gam-zoh ra'iti ani ki mi-yad ha'Elohim hi</em> — 'This also, I saw, is from the hand of God.' The pivot: the carpe diem counsel is not mere hedonism but a recognition that the capacity for enjoyment is itself a divine gift (<em>mi-yad ha'Elohim</em>, 'from God's hand' — the hand that provides).</p>",
        "25": "<p><strong>Ki mi yokhal ve-mi yachush chutz mimmenni</strong> — 'For apart from God, who can eat or find enjoyment?' The MT reads <em>mimmenni</em> ('apart from me') — a first-person form — but the LXX reads <em>mimmennu</em> ('apart from him,' i.e., God). Most English versions follow the LXX here. The MT reading (the Teacher speaking in his own voice) would mean: 'who can enjoy apart from what I have experienced?' — a claim that the experiment was comprehensive. Either reading supports the theological point: enjoyment is not self-generated; it requires a giver (v.24: 'from the hand of God') or a framework (the Teacher's wisdom). The verse is brief — a single rhetorical question — where the point is made entirely by the question's force.</p>",
        "26": "<p><strong>Ki le-adam she-tov lefanav natan hokmah ve-da'at ve-simha</strong> — 'For God gives wisdom, knowledge, and joy to the one who pleases him.' The triple gift (wisdom, knowledge, joy) to the one who 'is good before him' (<em>tov lefanav</em>) — the idiom 'good before God' means morally acceptable, pleasing to God's sight. <em>Ve-la-chote natan inyan le'esof ule-khnas</em> — 'but to the sinner he assigns the task of gathering and accumulating.' The sinner's <em>inyan</em> (business) is <em>le'esof ule-khnas</em> (to gather and to accumulate) — both verbs describe hoarding. <em>Litet le-tov lifnei ha'Elohim</em> — 'only to hand it over to the one who pleases God.' The ironic reversal: the sinner labors to accumulate, then transfers it to the God-pleaser at death. <em>Gam-zeh havel ure'ut ruach</em> — the full verdict formula closes the chapter.</p>"
    },
    "3": {
        "1": "<p><strong>Le-khol ze-man ve-et le-khol-chefetz tahat hashamayim</strong> — 'For everything there is a season, and a time for every purpose under heaven.' The poem of ch. 3 opens with two near-synonyms: <em>ze-man</em> (H2165, an appointed time/fixed time) and <em>et</em> (H6256, a time/occasion). <em>Ze-man</em> is the more precise, carrying the sense of a set appointment (related to <em>zamam</em>, to plan/purpose). <em>Chefetz</em> (H2656) means 'purpose/delight/desire' — what one delights in or intends. The verse frames the poem: it is not randomness but a structured schedule of appointments that governs all activity. The question the poem poses is who sets that schedule.</p>",
        "2": "<p><strong>Et laledet ve-et lamut</strong> — 'A time to be born, and a time to die.' The 14-pair poem (vv.2-8) uses a merism structure: naming the two extremes implies all that lies between. Birth and death are the ultimate brackets of human life. <em>Et lata'at ve-et la'akor natu'a</em> — 'a time to plant, and a time to uproot.' The agricultural verbs shift the focus: if birth/death are biological facts, planting/uprooting are volitional — human decisions about when to invest and when to abandon. Both pairs fall within the <em>ze-man</em>/<em>et</em> structure: all human decisions, not just biological events, have their appointed time.</p>",
        "3": "<p><strong>Et laharog ve-et lirpo</strong> — 'A time to kill, and a time to heal.' The verb <em>harag</em> (to kill/slay) is used for both murder and legitimate killing; context determines the moral valence. The Teacher does not categorize: the poem is descriptive of the range of human activities, not prescriptive of which are justified. <em>Et lifrotz ve-et livnot</em> — 'a time to break down, and a time to build up.' The pair describes demolition and construction — both are valid activities within the appointed seasons. The poem does not say which is preferable in the abstract; each has its time.</p>",
        "4": "<p><strong>Et livkot ve-et liskhok</strong> — 'A time to weep, and a time to laugh.' The emotional pairs: grief and joy, mourning and dancing. Jesus cites this kind of wisdom (implicitly) when he says 'Blessed are those who mourn' (Matt 5:4) and 'Blessed are you who weep now, for you shall laugh' (Luke 6:21). The Teacher observes the structure of appointed emotional seasons; Jesus announces the eschatological reversal that the Teacher, 'under the sun,' cannot see. <em>Et safod ve-et rekhod</em> — 'a time to mourn, and a time to dance.' <em>Safad</em> (to mourn/beat the breast) and <em>raqad</em> (to dance/leap) are the emotional extremes of communal response — mourning at funerals, dancing at festivals.</p>",
        "5": "<p><strong>Et le-hashlikh avanim ve-et knos avanim</strong> — 'A time to throw away stones, and a time to gather stones.' This pair has generated the most interpretive debate in the poem — the practice of throwing and gathering stones is not self-evidently meaningful. Ancient interpretations include: (1) agricultural land clearing (throwing stones from a field) and gathering them for building; (2) a euphemism for sexual activity (rabbinic); (3) military sieges (throwing stones at fortified cities) and reconstruction after them. The ambiguity is likely intentional — it resists resolution, illustrating the poem's point about inscrutable timing. <em>Et lavkot ve-et lirhod</em> — 'a time to embrace, and a time to refrain from embracing' — physical intimacy has its appointed time.</p>",
        "6": "<p><strong>Et levaqesh ve-et le'abed</strong> — 'A time to seek, and a time to lose.' The pair contrasts active seeking (<em>baqash</em>, to seek/search) with passive loss (<em>abad</em>, to perish/be lost). The choice to seek and the fact of loss both fall within appointed seasons. <em>Et lishmor ve-et le-hashlikh</em> — 'a time to keep, and a time to throw away.' The pair of <em>shamar</em> (to keep/guard — the same verb as keeping covenant, Exod 20:6) and <em>hashlikh</em> (to throw/cast away) extends the stone-gathering/throwing pair: sometimes what one has faithfully kept must be surrendered.</p>",
        "7": "<p><strong>Et li-qro'a ve-et litfor</strong> — 'A time to tear, and a time to sew.' Tearing garments was the ancient gesture of grief (Gen 37:29; Job 1:20); sewing them represented the end of mourning. The pair encapsulates the rhythm of grief and recovery. <em>Et la-hachshot ve-et le-dabber</em> — 'a time to keep silence, and a time to speak.' Wisdom literature consistently values the discipline of silence: 'He who restrains his words has knowledge' (Prov 17:27). But silence and speech each have their appointed time — the wisdom is in discerning which the moment calls for.</p>",
        "8": "<p><strong>Et le'ehov ve-et lisno</strong> — 'A time to love, and a time to hate.' The climactic final pair of human relationships. Love and hate are presented without moral commentary: the poem describes the full range of human relational experience as having an appointed time structure. <em>Et milchamah ve-et shalom</em> — 'a time for war, and a time for peace.' The social/political level: war and peace are not merely human choices but fall within the structured seasons of the cosmos. The poem closes at the political macro-level after opening with the biological micro-level (birth and death), encompassing the full range of human experience.</p>",
        "9": "<p><strong>Mah-yitron ha-oseh ba'asher hu amel</strong> — 'What gain does the worker have from his toil?' The question of 1:3 (<em>mah yitron</em>) recurs after the poem — but now the context is different. The poem has shown that all activities have their appointed time; the question returns: if all things have their time and everything cycles, what lasting advantage accumulates? The question is answered in vv.10-15: there is no <em>yitron</em> from the worker's perspective, but God's perspective gives meaning to what appears cyclical and futile.</p>",
        "10": "<p><strong>Ra'iti et-ha-inyan asher natan Elohim livnei ha-adam la'anot bo</strong> — 'I have seen the business that God has given to the children of man to be occupied with.' The word <em>inyan</em> recurs (cf. 1:13): 'unhappy business.' The repetition links this reflection to the opening investigation: the same <em>inyan</em> that God assigned (1:13) is the subject of continued observation. The Teacher's empirical method — seeing, observing, examining — governs his procedure throughout.</p>",
        "11": "<p><strong>Et-hakol asah yafeh be-ito</strong> — 'He has made everything beautiful in its time.' The word <em>yafeh</em> (beautiful/appropriate) is the same root as the superlative of the Song of Songs (1:15-16: 'you are beautiful'). God's making of 'everything beautiful in its time' affirms the goodness of the appointed schedule — each thing is beautiful precisely when it occurs in its proper time. <em>Gam et-ha-olam natan be-libbam</em> — 'Also, he has put eternity in the human heart.' <em>Olam</em> (H5769) — normally 'forever/eternity/age' — is placed 'in the human heart' as a divine implantation. This is the theological key to why the Teacher's investigation is frustrated: humans have an awareness of eternity (<em>olam</em>) but cannot 'find out what God has done from beginning to end.' The <em>olam</em>-capacity creates the longing; the mortality creates the frustration. The NT's resolution is resurrection: in Christ, the <em>olam</em>-longing is met eschatologically.</p>",
        "12": "<p><strong>Yada'ti ki ein tov bam ki im-lismoch ve-la'asot tov be-chayyav</strong> — 'I know that there is nothing better for them than to rejoice and to do good throughout their life.' The carpe diem counsel now includes an ethical dimension: <em>ve-la'asot tov</em> ('and to do good'). Enjoyment and goodness are paired — the positive counsel is not hedonism but joyful moral living. The addition of 'do good' distinguishes Ecclesiastes' counsel from mere pleasure-seeking: the appointed seasons include seasons for ethical action, not just personal enjoyment. <em>Be-chayyav</em> — 'throughout his life' — the temporal scope: not a single moment of pleasure but a stance toward the whole of life.</p>",
        "13": "<p><strong>Ve-gam kol-ha-adam sheyokhal ve-shata ve-ra'ah tov be-khol amalo</strong> — 'And that everyone should eat and drink and take pleasure in his toil.' The formula from 2:24 recurs with slight variation: 'every person' (<em>kol-ha-adam</em>) broadens the counsel from the singular experiment to a universal principle. <em>Matat Elohim hi</em> — 'this is God's gift.' <em>Matat</em> (H4991, gift) from <em>natan</em> (to give) — the capacity for enjoyment is a divine donation, not a human achievement. The passive construction 'is God's gift' is stronger than 2:24's 'from the hand of God': the gift character of enjoyment is now stated as a theological proposition, not just an observation.</p>",
        "14": "<p><strong>Yada'ti ki kol-asher ya'aseh ha'Elohim hu yih-yeh le'olam</strong> — 'I know that whatever God does endures forever.' <em>Le'olam</em> (forever) — God's acts are characterized by the <em>olam</em> permanence that human acts lack. <em>Ein le-hosif alav ve-ein ligro'a mimmenhu</strong> — 'nothing can be added to it and nothing taken away from it.' This is the ontological description of divine sovereignty over creation: God's acts are complete and unalterable. <em>Ve-ha'Elohim asah she-yir'u milfanav</em> — 'God has done it so that people would fear him.' The purpose of divine immutability is the fear of God (<em>yir'ah</em>, H3374) — the reverential awe that is the beginning of wisdom (Prov 1:7). God's unchangeability, rather than making him remote, creates the conditions for appropriate human response.</p>",
        "15": "<p><strong>Mah-shehayah kebar hu</strong> — 'What is has already been.' The cyclical observation of 1:9 is restated but now in a theological frame: it is not merely a human observation about repetition but a characterization of how God relates to history. <em>Ve-asher lih-yot kebar hayah ve-ha'Elohim yevaqesh et-nirdaf</em> — 'and what is to be already has been. God seeks out what has been driven away.' The final phrase is the most difficult in this verse: <em>et-nirdaf</em> (H7291, the hunted/driven away/pursued one) — God 'seeks' what has been pushed aside, marginalized, or seemingly lost. Some read this as a recycling of the past; others as God pursuing justice for the driven-away (the oppressed, cf. 3:16). The theological claim is that God's sovereignty over time means nothing falls permanently outside his attention.</p>",
        "16": "<p><strong>Ve-od ra'iti tahat hashemesh meqom ha-mishpat shamah ha-resha</strong> — 'Moreover, I saw under the sun that in the place of justice, even there was wickedness.' <em>Mishpat</em> (H4941, justice/judgment) and <em>tzedeq</em> (righteousness) are the two pillars of YHWH's throne (Ps 89:14); here both are perverted in the institutions (<em>maqom</em>, place) designed to embody them. The corruption of the court system — the place of justice becoming the place of wickedness — is the most socially devastating form of <em>hevel</em>: the system designed to protect the oppressed becomes a tool of oppression. The Teacher does not call for revolution; he observes and waits for v.17's resolution.</p>",
        "17": "<p><strong>Amarthi ani be-libbi et-ha-tzadiq ve-et-ha-rasha yishpot ha'Elohim</strong> — 'I said in my heart, &#8220;God will judge the righteous and the wicked.&#8221;' The theological response to v.16's corruption is not despair but confidence in divine judgment. <em>Ki et le-khol-chefetz ve-al kol-hama'aseh sham</em> — 'for there is a time for every matter and for every work.' The word <em>sham</em> ('there') is puzzling: where is 'there'? Some read it as 'then' (temporal); others as a reference to the divine court. The appointed-time structure of the poem (3:1-8) returns: the corruption of human courts will have its appointed time of divine judgment. The <em>et</em>/<em>ze-man</em> structure that governs all things governs judgment too.</p>",
        "18": "<p><strong>Amarthi ani be-libbi al-dibrat benei ha-adam</strong> — 'I said in my heart with regard to the children of man.' <em>Dibrat</em> (H1700) — rare word; 'on account of/concerning/for the sake of' — the Teacher's reflection is directed specifically at the human situation. <em>Levar'am ha'Elohim ve-lir'ot she-hem-behemah hemah lahem</em> — 'that God is testing them so they may see that they themselves are but animals.' The verb <em>berar</em> (H1305, to sift/test/purify) appears in a reflexive form: God is separating/testing humanity to show them something about themselves. The word <em>behemah</em> (beast/animal, H929) is the sharp term: the Teacher makes the unsentimental claim that from a sub-eschatological perspective, humans and beasts share the same creaturely mortality.</p>",
        "19": "<p><strong>Ki miqreh benei ha-adam u-miqreh ha-behemah u-miqreh echad lahem</strong> — 'For what happens to the children of man is what happens to the beasts; the same thing happens to both.' The word <em>miqreh</em> (event/fate) appears three times in this verse — the repetition is emphatic. <em>Ke-mot zeh ken mot zeh</strong> — 'As one dies, so dies the other.' The brevity of the construction heightens the impact: no expansion, no qualification. <em>Ve-ruach echad le-khol</em> — 'They all have the same breath/spirit.' <em>Ruach echad</em> (one spirit/breath) — the single <em>ruach</em> that gives life to both human and animal, and whose departure means death for both. <em>U-motar ha-adam min-ha-behemah ayin</em> — 'man has no advantage over the beasts' — <em>motar</em> (H4195, advantage/profit) is yet another word in the <em>yitron</em> family; from the perspective of mortality alone, there is no human advantage. <em>Ki hakol havel</em> — 'All is futility.' The only verse in this section that ends with <em>havel</em> alone, without 're'ut ruach.'</p>",
        "20": "<p><strong>Hakol holekh el-maqom echad</strong> — 'All go to one place.' <em>Maqom echad</em> (one place) — the shared destination of all mortals: the grave, Sheol. The universality is total: not 'some' or 'most' but 'all.' <em>Hakol hayah min-ha'afar ve-hakol shav el-ha'afar</em> — 'All are from the dust, and all return to dust.' The echo of Genesis 3:19 is unmistakable (<em>ki afar atah ve-el-afar tashuv</em>: 'for you are dust, and to dust you shall return') — the Teacher is applying the curse of Gen 3 to the full range of created mortality. The Teacher does not cite Genesis, but his observation is rooted in the same creaturely condition that the fall confirmed.</p>",
        "21": "<p><strong>Mi yode'a ruach benei ha-adam ha-olah hi lema'lah</strong> — 'Who knows whether the spirit of man goes upward?' The <em>mi yode'a</em> ('who knows?') formula marks the limit of 'under the sun' knowledge. The question about the destiny of the human <em>ruach</em> is left open: goes upward (to God) or downward (like the animal's spirit, to the earth)? <em>Ve-ruach ha-behemah hayoredet hi lemattah la'aretz</em> — 'and the spirit of the beast goes downward to the earth?' The Teacher does not deny the resurrection — he identifies it as beyond the epistemological reach of sub-eschatological wisdom. The NT's announcement of resurrection is the answer to precisely this <em>mi yode'a</em>: the resurrection of Christ demonstrates that the human <em>ruach</em> does indeed have an upward destiny, because Christ's has shown the way (1 Cor 15:20).</p>",
        "22": "<p><strong>Ve-ra'iti ki ein tov me-asher yismach ha-adam be-ma'asav</strong> — 'So I saw that there is nothing better than that a man should rejoice in his work.' The carpe diem counsel recurs, now grounded in the preceding meditation on mortality and divine judgment. Rejoicing in work is the positive response to the Teacher's epistemological limit: since 'who knows' what comes after, the portion available now — enjoyment in work — is the wise response. <em>Ki hu helqo</em> — 'for that is his portion.' <em>Helqo</em> (his portion) — the concept introduced at 2:10: the <em>helq</em> that actually belongs to the person, as opposed to the accumulated <em>amal</em> that passes to another. <em>Ki mi yevi'ennu lir'ot bemah sheyih-yeh acharav</em> — 'For who can bring him to see what will be after him?' The future is beyond sight; the present is available. This is not fatalism but realism about the limits of human knowledge.</p>"
    },
    "4": {
        "1": "<p><strong>Ve-shavthi ani va-er'eh et-kol-ha'ashukot asher na'asim tahat hashemesh</strong> — 'I turned and considered all the acts of oppression done under the sun.' The verb <em>shav</em> (to turn/return) marks a new investigation — the Teacher redirects his attention from the times-poem meditation to social observation. <em>Ashukot</em> (H6217, acts of oppression) from <em>ashaq</em> (to oppress/defraud/extort). <em>Ve-hineh dim'at ha'ashukot ve-ein lahem menachem</em> — 'I saw the tears of the oppressed — they had no one to comfort them.' The pathos here is as acute as anywhere in the book: <em>menachem</em> (H5162, comforter) — the absent comforter. Lamentations 1:2 uses the same construction for Jerusalem's weeping with no comforter (<em>ein menachem</em>). The Teacher's observation anticipates Lamentations' grief without offering the resolution that comes only in the eschatological consolation (Isa 40:1: 'Comfort, comfort my people').</p>",
        "2": "<p><strong>Ve-shabach ani et-ha-metim she-kebar metu</strong> — 'So I counted the dead who have already died more fortunate than the living.' <em>Shabach</em> (H7623, to praise/commend/declare fortunate) — the Teacher 'praises' the dead. The word is strong: this is public declaration of the dead's superior condition given the oppression of v.1. <em>Min-ha-chayyim asher hemmah chayyim adenat</em> — 'more fortunate than the living who are still alive.' The comparison is conditional on the context of oppression: death ends the experience of watching oppression without remedy. This is not a death-wish but an honest response to what the Teacher has observed.</p>",
        "3": "<p><strong>Ve-tov mishneihem et asher-adenat lo hayah</strong> — 'But better off than either is the one not yet born.' The better-off formula <em>tov</em> … <em>mi</em> (good/better … than) creates a descending scale: living (worst), dead (better), unborn (best). <em>Asher lo-ra'ah et-hama'aseh hara' sheassoh tahat hashemesh</em> — 'who has not seen the evil that is done under the sun.' Not seeing the evil is the unborn's advantage. The Teacher's bitter logic: the best position is not to have begun. This is the nadir of his social observation — not a permanent conclusion but the honest extreme of what oppression without remedy looks like.</p>",
        "4": "<p><strong>Ve-ra'iti ani et-kol amal ve-et kol kishron hama'aseh ki hi qin'at ish mere'ehu</strong> — 'Then I saw that all toil and every skilled achievement springs from a person's envy of his neighbor.' The word <em>qin'ah</em> (H7068, envy/jealousy/zeal) here in its negative sense: social rivalry as the hidden motor of industriousness. <em>Kishron</em> (H3788, skill/efficiency) appeared at 2:21 for the wise person's abilities. The Teacher now identifies that much of what appears to be virtuous skill (<em>kishron</em>) is actually rivalry-driven (<em>qin'ah</em>). <em>Gam-zeh havel ure'ut ruach</em> — the full verdict: industry driven by envy produces the same futile result as the other experiments.</p>",
        "5": "<p><strong>Ha-kesil chofek et-yadav ve-okhal et-besaro</strong> — 'The fool folds his hands and devours himself.' The proverbial image of the fool who folds his hands (refuses to work) and thereby 'eats his own flesh' (consumes himself through idleness) is a counterpoint to v.4. The danger of v.4's observation (all toil is envy-driven) is the conclusion that one should do nothing; v.5 addresses that: idleness destroys too. The fool's hands, folded instead of working, turn inward and consume the person. The Teacher acknowledges the other side of the futility: not only is envy-driven labor futile, but its absence is self-destructive.</p>",
        "6": "<p><strong>Tov melo kaph nachath mi-melo chafnayyim amal ure'ut ruach</strong> — 'Better is one hand full of quietness than two hands full of toil and chasing the wind.' The <em>tov min</em> (better than) comparative proverb is a wisdom form used frequently in Proverbs and Ecclesiastes. <em>Nachath</em> (H5183, quietness/rest/contentment) — the posture of the person who has enough and rests. The comparison is between one hand of contentment and two hands of toil-with-futility: not that toil is worse than idleness, but that toil driven by acquisitive anxiety (<em>amal ure'ut ruach</em>) is worse than a simpler, quieter sufficiency. This is the Teacher's moderate counsel between the envy-driven overwork of v.4 and the self-consuming idleness of v.5.</p>",
        "7": "<p><strong>Ve-shavthi ani va-er'eh hevel tahat hashemesh</strong> — 'Again I turned and observed something futile under the sun.' The formulaic transition marks a new case study within the observation of futility. The repeated <em>shav</em> (turning) and <em>ra'ah</em> (seeing) signal the Teacher's methodological move to a new empirical case. This verse is transitional — its function is structural, introducing the case of the solitary miser in v.8.</p>",
        "8": "<p><strong>Yesh echad ve-ein sheni gam ben ve-ach ein-lo ve-ein kets le-khol amalo</strong> — 'Here is a solitary man with no companion — neither son nor brother — yet his labor has no end.' The portrait of isolated, purposeless accumulation: <em>echad</em> (one/alone) with neither son (<em>ben</em>) nor brother (<em>ach</em>) to inherit. <em>Ve-einenu sava' ashir</em> — 'and his eyes are never satisfied with wealth.' <em>Sava</em> (to be satisfied/full) — the same root as the eye's insatiation (1:8) and the sea that is never full (1:7): the accumulator joins the relentless cycles of insatiability. <em>U-le-mi ani amel ve-mechasar et-nafshi mi-tovah</em> — 'He never asks, &#8220;For whom am I working, and why am I denying myself any pleasure?&#8221;' <em>Mechasar nafshi</em> (depriving/denying my soul/life) — the irony: the miser deprives the very <em>nefesh</em> that the Teacher elsewhere counsels should 'see good' (2:24). <em>Gam-zeh hevel ve-inyan ra' hu</em> — the formula closes with <em>inyan ra'</em> (evil/unhappy business): the same judgment as 1:13 on the whole investigating project is now applied to purposeless accumulation.</p>",
        "9": "<p><strong>Tovim ha-shenayim min-ha-echad</strong> — 'Two are better than one.' The <em>tov min</em> comparative form now applies to social solidarity: the companionship that the solitary miser of v.8 lacks. <em>Asher yesh lahem sakar tov ba-amalam</em> — 'because they get a better return for their labor.' <em>Sakar tov</em> (good reward/return) — here, unusually, labor has a positive return when shared. The companionship proverbs (vv.9-12) do not reverse the verdict on <em>amal</em> generally but identify an exception: collaborative work produces returns that solitary accumulation does not.</p>",
        "10": "<p><strong>Ki im-yipolu ha-echad yaqim et-chavero</strong> — 'For if one falls, the other will lift his companion up.' <em>Chavero</em> (his companion/friend) — from <em>chaver</em> (H2270, companion/associate). The image is both literal (helping someone who has fallen physically) and figurative (one who helps another recover from misfortune). <em>Ve-oy lo le-echad sheyipol ve-ein sheni lahaqimo</em> — 'But terrible is the fate of the one who is alone when he falls — there is no one to help him up.' <em>Ve-oy lo</em> — 'woe to him' — the lament exclamation marks the severity. The contrast is vivid: the two-person situation has a solution (one lifts the other); the solitary situation has no solution.</p>",
        "11": "<p><strong>Gam im-yishkvu shenayim ve-cham lahem</strong> — 'Also, if two lie together they keep each other warm.' The practical wisdom is about survival in the cold — the ancient world before central heating required shared body warmth. <em>Le-echad eikh yitcham</em> — 'But how can one person keep warm alone?' The rhetorical question expects the answer: he cannot. The physical observation grounds the social teaching: community is not sentimental but functional — a matter of survival. This is the wisdom register of the companionship sayings, not romantic idealism.</p>",
        "12": "<p><strong>Ve-im-yitqfoh ha-echad ha-shenayim ya'amdu negdo</strong> — 'Though one person may be overpowered, two can stand their ground.' <em>Taqaf</em> (H8630, to overpower/prevail over) — the single person is vulnerable to overpowering; the two can resist. <em>Ve-ha-chut ha-meshulash lo be-mehera yinataq</em> — 'A cord of three strands is not quickly broken.' <em>Ha-chut ha-meshulash</em> (the three-stranded cord) — a proverb within the passage, adding a third element to the two-is-better-than-one observation. The three-strand cord is structurally stronger than a two-strand one because the strands brace each other at more angles. The proverb is not introducing a theological third party (though Christian readers have applied it to divine presence in marriage/community); it is extending the numerical observation: two is better than one, and three is more stable than two.</p>",
        "13": "<p><strong>Tov yeled misken ve-chakham me-melekh zaken u-kesil asher lo-yada lizhhar od</strong> — 'Better a poor but wise young man than an old and foolish king who no longer heeds counsel.' The <em>tov min</em> comparison returns: wisdom is a greater social resource than royal position when the king has ceased to be teachable. <em>Lo-yada lizhhar od</em> — 'who no longer heeds counsel' — literally 'who no longer knows to be warned.' <em>Zahir</em> (H2094, to warn/admonish/instruct) — the king who has stopped receiving instruction from others. The refusal of counsel is the signature of Proverbs' foolish king (Prov 12:15: 'the way of a fool is right in his own eyes'; 15:5: 'a fool despises his father's instruction').</p>",
        "14": "<p><strong>Ki mi-beit ha-asurim yatza limlokh</strong> — 'The young man rose from prison to the throne.' The passive movement from prison to throne — without active verb of ambition — suggests the Teacher is describing a type or historical case. <em>Ki gam be-malkuto nolad rash</em> — 'though he had been born poor in that very kingdom.' The origin of the wise young man is the most disadvantaged possible: prison and poverty. His rise despite these origins is the evidence that wisdom transcends status. The most natural historical referent is Joseph (Gen 39-41: imprisoned, then elevated to rule), though the Teacher does not name him; the pattern fits other cases as well (Daniel, Mordecai).</p>",
        "15": "<p><strong>Ra'iti et-kol-ha-chayyim ha-mehalkhim tahat hashemesh im ha-yeled ha-sheni</strong> — 'I saw all the living — those who walk under the sun — rally to the side of the second young man.' <em>Ha-yeled ha-sheni</em> (the second young man) — the 'second' (successor) who rallies popular support. The popular identification with the new young ruler is the moment of maximum promise for the young wise man who rose from prison. But v.16 will immediately undercut this popular support: it is transient.</p>",
        "16": "<p><strong>Ein kets le-khol ha-am le-khol asher hayah lifneihem</strong> — 'There was no end to all the people who followed him.' The limitless crowd — a picture of popular success at its peak. <em>Gam ha-acharonim lo yismechu vo</em> — 'yet those who come later will take no delight in him either.' The succession problem of chs. 2-3 recurs: the generation that follows will not find the same satisfaction in the successor that the contemporary generation found. Popular acclaim has the same horizon as every other form of <em>amal</em>: it does not outlast the generation that gave it. <em>Ki gam-zeh hevel ure'ut ruach</em> — the full verdict formula closes this social meditation. The pattern is sealed: from the isolated miser to the beloved king, all social realities of accumulation and acclaim fall under the same judgment.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'ecclesiastes')
    merge_comm(existing, ECCLESIASTES)
    save_comm('mkt-original', 'ecclesiastes', existing)
    print('Ecclesiastes 1–4 mkt-original written.')

